gold_sparql:
SELECT ?paper, ?year, ?dc_method_type_label, ?dc_method_name
        WHERE {
                ?paper orkgp:P31 ?contribution;
                       orkgp:P29 ?year.
                ?contribution a orkgc:C27001;
                              orkgp:P135046 ?serie.
                ?serie rdfs:label ?venue_name.

                ?contribution orkgp:P56008 ?data_collection.
                ?data_collection orkgp:P1005 ?dc_method;
                                 rdfs:label ?dc_label.
                ?dc_method orkgp:P94003 ?dc_method_type;
                           orkgp:P145012 ?dc_method_name.
                ?dc_method_type rdfs:label ?dc_method_type_label.

                FILTER(?dc_method_type_label = "secondary research"^^xsd:string)
                FILTER (?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }

SELECT DISTINCT ?paper ?year ?paperLabel ?guidelineAvailabilityLabel
  WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution rdf:type orkgc:C121001;
        orkgp:P181031 ?annotationProcess .
      ?paper orkgp:P29 ?year .

      ?annotationProcess orkgp:P181036 ?annotationScheme .
      ?annotationScheme orkgp:P181038 ?guidelineAvailability .

      OPTIONAL {?paper rdfs:label ?paperLabel .}
      OPTIONAL {?guidelineAvailability rdfs:label ?guidelineAvailabilityLabel .}
  }ORDER BY ?paperLabel

SELECT DISTINCT ?contribution ?paper ?paperLabel ?RETaskLabel ?NLPTaskTypeLabel ?NLPTaskTypeDescription
    WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
                          orkgp:P181002 ?RETask;
                          orkgp:P181003 ?NLPTask .

        ?NLPTask orkgp:P181004 ?NLPTaskType .
        OPTIONAL{?NLPTaskType orkgp:description ?NLPTaskTypeDescription .}

        OPTIONAL { ?paper rdfs:label ?paperLabel . }
        OPTIONAL { ?RETask rdfs:label ?RETaskLabel . }
        OPTIONAL { ?NLPTaskType rdfs:label ?NLPTaskTypeLabel . }
    }
    ORDER BY ?contribution ?paperLabel ?NLPTaskTypeLabel

SELECT DISTINCT ?contribution ?paper ?paperLabel ?numberOfAnnotators ?NLPTaskTypeLabel ?annotatorAssignmentLabel ?levelOfExpertiseLabel ?annotatorIdentityLabel
    WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
                 orkgp:P181031 ?annotationProcess;
                 orkgp:P181003 ?NLPTask .

         ?NLPTask orkgp:P181004 ?NLPTaskType .
         ?annotationProcess orkgp:P181032 ?annotator .
         ?annotator orkgp:P59120 ?numberOfAnnotators;
                    orkgp:P181033 ?annotatorAssignment;
                    orkgp:P181034 ?levelOfExpertise;
                    orkgp:P181035 ?annotatorIdentity .

        OPTIONAL { ?NLPTaskType rdfs:label ?NLPTaskTypeLabel . }
        OPTIONAL {?paper rdfs:label ?paperLabel .}
        OPTIONAL {?annotatorAssignment rdfs:label ?annotatorAssignmentLabel .}
        OPTIONAL {?levelOfExpertise rdfs:label ?levelOfExpertiseLabel .}
        OPTIONAL {?annotatorIdentity rdfs:label ?annotatorIdentityLabel .}
    } ORDER BY ?paperLabel

SELECT ?paper, ?dc_method_type_label, ?dc_method_name
        WHERE {
                ?paper orkgp:P31 ?contribution;
                       orkgp:P29 ?year.
                ?contribution a orkgc:C27001;
                              orkgp:P135046 ?serie.
                ?serie rdfs:label ?venue_name.

                ?contribution orkgp:P56008 ?data_collection.
                ?data_collection orkgp:P1005 ?dc_method;
                                 rdfs:label ?dc_label.
                ?dc_method orkgp:P94003 ?dc_method_type;
                           orkgp:P145012 ?dc_method_name.
                ?dc_method_type rdfs:label ?dc_method_type_label.

                FILTER(?dc_method_type_label = "secondary research"^^xsd:string)
                FILTER (?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }

SELECT DISTINCT ?paper ?paperLabel ?evaluation_metricLabel
        WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
                orkgp:HAS_EVALUATION ?evaluation .
        ?evaluation orkgp:P110006 ?evaluation_metric .

        OPTIONAL {?paper rdfs:label ?paperLabel .}
        OPTIONAL {?evaluation_metric rdfs:label ?evaluation_metricLabel .}
        } ORDER BY ?paperLabel

SELECT DISTINCT ?contribution ?paper ?paperLabel ?RETaskLabel ?NLPTaskInputLabel
    WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
             orkgp:P181002 ?RETask;
                         orkgp:P181003 ?NLPTask.
        ?NLPTask orkgp:P181005 ?NLPTaskInput .

        OPTIONAL {?paper rdfs:label ?paperLabel .}
        OPTIONAL {?RETask rdfs:label ?RETaskLabel .}
        OPTIONAL {?NLPTaskInput rdfs:label ?NLPTaskInputLabel .}
    }ORDER BY ?contribution

SELECT DISTINCT ?contribution ?paper ?paperLabel ?baseline_typeLabel
    WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
             orkgp:HAS_EVALUATION ?evaluation .
        ?evaluation orkgp:P181051 ?baseline_comparison .
        ?baseline_comparison orkgp:P181052 ?baseline_type .

        OPTIONAL {?paper rdfs:label ?paperLabel .}
        OPTIONAL {?baseline_type rdfs:label ?baseline_typeLabel .}
    } ORDER BY ?contribution

SELECT DISTINCT ?contribution ?paper ?paperLabel ?NLPdataformatLabel
    WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
                 orkgp:P181011 ?NLPdataset .
        ?NLPdataset orkgp:P181022 ?NLPdatatype .
        ?NLPdatatype orkgp:P181023 ?NLPdataformat .

        OPTIONAL {?paper rdfs:label ?paperLabel .}
        OPTIONAL {?NLPdataformat rdfs:label ?NLPdataformatLabel .}
    } ORDER BY ?contribution

SELECT DISTINCT ?contribution ?paper ?paperLabel ?intercoderReliabilityMetricLabel
    WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
                 orkgp:P181031 ?annotationProcess .
        ?annotationProcess orkgp:P181041 ?annotationAgreement .
        ?annotationAgreement orkgp:P181042 ?intercoderReliabilityMetric .

        OPTIONAL {?paper rdfs:label ?paperLabel .}
        OPTIONAL {?intercoderReliabilityMetric rdfs:label ?intercoderReliabilityMetricLabel .}
    } ORDER BY ?contribution

SELECT DISTINCT ?paper ?paperLabel ?researchQuestion ?questionWording
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .
    ?venue rdfs:label ?venue_name .
    ?contribution orkgp:P37330 ?researchQuestion .

    OPTIONAL { ?researchQuestion orkgp:P44139 ?questionWording . }
    ?paper rdfs:label ?paperLabel .

    FILTER NOT EXISTS {
        ?researchQuestion orkgp:P41928 ?questionType .
        ?questionType rdfs:label ?questionTypeLabel .
  }
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
ORDER BY ?paperLabel ?questionWording

SELECT DISTINCT ?paper ?paperLabel ?researchQuestion ?subquestion ?subquestionWording
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .
    ?venue rdfs:label ?venue_name .

    ?contribution orkgp:P37330 ?researchQuestion .
    ?researchQuestion orkgp:P57000 ?subquestion .

    OPTIONAL { ?subquestion orkgp:P44139 ?subquestionWording . }

    ?paper rdfs:label ?paperLabel .

    FILTER NOT EXISTS {
        ?subquestion orkgp:P41928 ?subquestionType .
        ?subquestionType rdfs:label ?subquestionTypeLabel .
    }
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
ORDER BY ?paperLabel ?subquestionWording

SELECT DISTINCT ?paper ?paperLabel ?hypothesis ?hypothesisStatement ?hypothesisTypeLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P15124 ?dataAnalysis .

    ?venue rdfs:label ?venue_name .
    ?dataAnalysis rdfs:label ?da_label ;
                  orkgp:P56043 ?inferentialStatistics .

    ?inferentialStatistics orkgp:P30001 ?hypothesis .
    ?hypothesis orkgp:P56046 ?hypothesisStatement .

    OPTIONAL {
        ?hypothesis orkgp:P41703 ?hypothesisType .
        OPTIONAL { ?hypothesisType rdfs:label ?hypothesisTypeLabel . }
    }

    ?paper rdfs:label ?paperLabel .

    FILTER(STR(?venue_name) = "IEEE International Requirements Engineering Conference")
    FILTER(LCASE(STR(?da_label)) != "no analysis")

    FILTER(
        !BOUND(?hypothesisType)
        || !BOUND(?hypothesisTypeLabel)
        || LCASE(STR(?hypothesisTypeLabel)) = "no type"
    )
}
ORDER BY ?paperLabel ?hypothesisStatement

SELECT ?paper ?paperLabel
       (COUNT(DISTINCT ?subquestion) AS ?subquestionCount)
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?serie .

    OPTIONAL {
        ?serie rdfs:label ?venue_name .
    }
    OPTIONAL {
        ?paper rdfs:label ?paperLabel .
    }

    OPTIONAL {
        ?contribution orkgp:P37330 ?researchQuestion .
        ?researchQuestion orkgp:P57000 ?subquestion .
    }

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?paper ?paperLabel
ORDER BY DESC(?subquestionCount) ?paperLabel

SELECT DISTINCT ?guidelineAvailability ?guidelineAvailabilityLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181031 ?annotationProcess .

  ?annotationProcess orkgp:P181036 ?annotationScheme .
   ?annotationScheme   orkgp:P181038 ?guidelineAvailability .

  OPTIONAL { ?guidelineAvailability rdfs:label ?guidelineAvailabilityLabel . }
}
ORDER BY ?guidelineAvailability

ASK {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 .

    ?contribution orkgp:HAS_EVALUATION ?evaluation .
    ?evaluation orkgp:P181051 ?baselineComparison .
    ?baselineComparison rdfs:label ?baselineComparisonLabel .

    FILTER(LCASE(STR(?baselineComparisonLabel)) != "not reported")

    FILTER(
        NOT EXISTS {
        ?baselineComparison orkgp:P181052 ?baselineType .
        ?baselineType rdfs:label ?baselineTypeLabel .
        FILTER(LCASE(STR(?baselineTypeLabel)) != "not reported")
        }
        ||
        NOT EXISTS {
        ?baselineComparison orkgp:P181053 ?baselineDetail .
        FILTER(LCASE(STR(?baselineDetail)) != "not reported")
        }
    )
}

SELECT ?question_type ?question_typeLabel
       ?method_type ?method_typeLabel
       (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    {
        SELECT DISTINCT ?paper ?paperLabel ?question_type ?question_typeLabel ?method_type ?method_typeLabel
        WHERE {
            ?paper orkgp:P31 ?contribution .

            OPTIONAL { ?paper rdfs:label ?paperLabel . }

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P37330 ?research_question ;
                          orkgp:P56008 ?data_collection .

            ?venue rdfs:label ?venue_name .

            ?research_question orkgp:P41928 ?question_type .
            ?data_collection rdfs:label ?dc_label ;
                             orkgp:P1005 ?dc_method .
            ?dc_method orkgp:P94003 ?method_type .

            OPTIONAL { ?question_type rdfs:label ?question_typeLabel . }
            OPTIONAL { ?method_type rdfs:label ?method_typeLabel . }

            FILTER(?dc_label != "no collection"^^xsd:string)
            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
    }
}
GROUP BY ?question_type ?question_typeLabel ?method_type ?method_typeLabel
ORDER BY DESC(?paper_count) ?question_typeLabel ?method_typeLabel

SELECT ?year
       ?research_paradigm ?research_paradigmLabel
       ?data_type ?data_typeLabel
       ?analysis_strategy
       (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    ?paper orkgp:P31 ?contribution ;
           orkgp:P29 ?year .

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P57003 ?research_paradigm ;
                  orkgp:P56008 ?data_collection ;
                  orkgp:P15124 ?data_analysis .

    ?venue rdfs:label ?venue_name .
    ?data_collection rdfs:label ?dc_label ;
                     orkgp:DATA ?research_data .
    ?data_analysis rdfs:label ?da_label .

    ?research_data orkgp:P7055 ?data_type .

    OPTIONAL { ?research_paradigm rdfs:label ?research_paradigmLabel . }
    OPTIONAL { ?data_type rdfs:label ?data_typeLabel . }

    {
        ?data_analysis orkgp:P56043 ?inferential_statistics .
        BIND("inferential statistics"^^xsd:string AS ?analysis_strategy)
    }
    UNION
    {
        ?data_analysis orkgp:P56048 ?descriptive_statistic .
        BIND("descriptive statistic"^^xsd:string AS ?analysis_strategy)
    }
    UNION
    {
        ?data_analysis orkgp:P57016 ?machine_learning .
        BIND("machine learning"^^xsd:string AS ?analysis_strategy)
    }

    FILTER(?dc_label != "no collection"^^xsd:string)
    FILTER(?da_label != "no analysis"^^xsd:string)
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?year ?research_paradigm ?research_paradigmLabel ?data_type ?data_typeLabel ?analysis_strategy
ORDER BY ?year DESC(?paper_count) ?research_paradigmLabel ?data_typeLabel ?analysis_strategy

SELECT DISTINCT ?year WHERE {
  ?paper orkgp:P31 ?contribution ;
    orkgp:P29 ?year .
  ?contribution a orkgc:C121001 ;
    orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181032 ?annotator .
  ?annotator orkgp:P59120 ?numAnnotators .
  FILTER(?numAnnotators = 2)
}

SELECT DISTINCT ?locationType ?locationTypeLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181011 ?dataset  .
  ?dataset orkgp:license ?license .
  ?license orkgp:P181026 ?publicAvailability .
  ?publicAvailability rdfs:label ?publicAvailabilityLabel .
  FILTER(LCASE(STR(?publicAvailabilityLabel)) = LCASE("yes"))
  ?dataset orkgp:P181028 ?location .
  ?location orkgp:P181030 ?locationType .
  OPTIONAL { ?locationType rdfs:label ?locationTypeLabel . }
}

SELECT DISTINCT ?paper ?paperLabel WHERE {
  ?paper orkgp:P29 ?year .
  FILTER(STR(?year) = "2023")
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 .
  ?contribution orkgp:P181046 ?approach .
  ?approach orkgp:release ?release .
  ?release orkgp:P1003 ?releaseUrl .
  OPTIONAL { ?paper rdfs:label ?paperLabel }
}

SELECT DISTINCT ?paper ?paperLabel ?locationTypeLabel ?url
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 .
  ?contribution orkgp:P181011 ?dataset .
  ?dataset orkgp:P181028 ?datasetLocation .
  ?datasetLocation orkgp:P181030 ?locationType .
  ?datasetLocation orkgp:P1003 ?url .
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?locationType rdfs:label ?locationTypeLabel . }
}
ORDER BY ?paperLabel ?locationTypeLabel ?url
